#![allow(non_upper_case_globals)]
#![allow(non_camel_case_types)]
#![allow(non_snake_case)]
#![allow(clippy::upper_case_acronyms)]

use std::sync::{Mutex, OnceLock};
use tracing::info;
use tracing_appender::non_blocking::WorkerGuard;
// SqlCpError enum variants generated by bindgen from sqlcrypt.h
use SqlCpError::{
    scp_err_InsufficientBuffer, scp_err_InvalidArgument, scp_err_NotFound, scp_err_NotSupported,
    scp_err_Success,
};

// UTF-16 LE encoding of "Cosmian KMS EKM Provider".
// Per the SQL Crypto API spec, SqlCpStr.ws does NOT need to be
// null-terminated; the `cb` field (byte count) is the sole length authority.
// We include a trailing 0x0000 anyway as a safety measure in case any
// internal SQL Server code path reads past `cb`, but it must NOT be counted
// in `cb`.  The slice lives for the lifetime of this DLL load.
static PROVIDER_NAME_UTF16: &[u16] = &[
    0x43, 0x6F, 0x73, 0x6D, 0x69, 0x61, 0x6E, // C o s m i a n
    0x20, //  (space)
    0x4B, 0x4D, 0x53, // K M S
    0x20, //  (space)
    0x45, 0x4B, 0x4D, // E K M
    0x20, //  (space)
    0x50, 0x72, 0x6F, 0x76, 0x69, 0x64, 0x65, 0x72,   // P r o v i d e r
    0x0000, // safety null — NOT counted in cb
];
// Character count of the string proper (excludes the safety null above).
const PROVIDER_NAME_CHARS: usize = 24;

// Bindgen-generated types from sqlcrypt.h
include!(concat!(env!("OUT_DIR"), "/bindings.rs"));

// ---------------------------------------------------------------------------
// Logging
//
// The rolling log file is written to:
//   %PROGRAMDATA%\Cosmian\EKM\logs\cosmian_ekm.log.<date>
// which on a typical Windows installation resolves to:
//   C:\ProgramData\Cosmian\EKM\logs\cosmian_ekm.log.<date>
//
// %PROGRAMDATA% is the correct root for a Windows service / DLL because
// SQL Server runs as a service account that has no user profile — only
// the machine-wide ProgramData directory is reliably writable.
//
// The companion configuration file should be placed at:
//   %PROGRAMDATA%\Cosmian\EKM\config.toml
// ---------------------------------------------------------------------------

/// Holds the `WorkerGuard` that keeps the non-blocking writer's background
/// thread alive.  Dropped (flushing all pending records) in
/// `SqlCryptFreeProvider`.
///
/// SQL Server may load and unload this DLL at its own discretion.  Each load
/// produces a fresh process image of the DLL with freshly-initialised statics,
/// so `OnceLock` naturally re-initialises on every DLL load without any
/// special handling.
static LOG_GUARD: OnceLock<Mutex<Option<WorkerGuard>>> = OnceLock::new();

/// Initialise the rolling-file subscriber exactly once.
/// Subsequent calls are no-ops.
fn init_logging() {
    // OnceLock::get_or_init guarantees the closure runs at most once even
    // under concurrent calls (e.g. two threads calling the provider entry
    // point simultaneously).
    LOG_GUARD.get_or_init(|| {
        // Resolve %PROGRAMDATA% at runtime so the code works regardless of
        // the Windows installation drive.
        let log_dir = std::env::var("PROGRAMDATA")
            .map(|p| {
                std::path::PathBuf::from(p)
                    .join("Cosmian")
                    .join("EKM")
                    .join("logs")
            })
            .unwrap_or_else(|_| std::path::PathBuf::from(r"C:\ProgramData\Cosmian\EKM\logs"));

        // Best-effort directory creation; if this fails the appender will
        // also fail and we fall through gracefully.
        let _ = std::fs::create_dir_all(&log_dir);

        let file_appender = tracing_appender::rolling::daily(&log_dir, "cosmian_ekm.log");
        let (non_blocking, guard) = tracing_appender::non_blocking(file_appender);

        tracing_subscriber::fmt()
            .with_writer(non_blocking)
            .with_max_level(tracing::Level::INFO)
            .with_ansi(false) // ANSI escape codes are meaningless in a plain log file
            .init();

        info!(
            log_dir = %log_dir.display(),
            "Cosmian EKM logging initialised"
        );

        Mutex::new(Some(guard))
    });
}

// ---------------------------------------------------------------------------
// Provider initialization
// ---------------------------------------------------------------------------

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptInitializeProvider() -> SqlCpError {
    init_logging();
    info!("SqlCryptInitializeProvider called");
    scp_err_Success
}

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptFreeProvider() -> SqlCpError {
    info!("SqlCryptFreeProvider called");
    // Drop the WorkerGuard so the background logging thread flushes and exits
    // cleanly before the DLL is unloaded.
    if let Some(cell) = LOG_GUARD.get() {
        if let Ok(mut guard) = cell.lock() {
            drop(guard.take());
        }
    }
    scp_err_Success
}

// ---------------------------------------------------------------------------
// Session management
// ---------------------------------------------------------------------------

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptOpenSession(
    p_auth: *const SqlCpCredential,
    p_sess: *mut SqlCpSession,
) -> SqlCpError {
    info!("SqlCryptOpenSession called");
    if p_sess.is_null() {
        return scp_err_InvalidArgument;
    }
    // Write a non-null sentinel as the session handle.
    // SQL Server passes this value back unchanged in every subsequent call;
    // we never dereference it until real session objects are implemented.
    let _ = p_auth;
    unsafe {
        *p_sess = 1usize as SqlCpSession;
    }
    scp_err_Success
}

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptCloseSession(p_sess: *mut SqlCpSession, f_abort: BOOLEAN) -> SqlCpError {
    info!("SqlCryptCloseSession called");
    // Nothing to free while session handles are sentinel values.
    let _ = (p_sess, f_abort);
    scp_err_Success
}

// ---------------------------------------------------------------------------
// Provider info
// ---------------------------------------------------------------------------

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptGetProviderInfo(p_provider_info: *mut SqlCpProviderInfo) -> SqlCpError {
    info!("SqlCryptGetProviderInfo called");
    if p_provider_info.is_null() {
        return scp_err_InvalidArgument;
    }
    unsafe {
        let info = &mut *p_provider_info;

        // Name byte-count: 24 UTF-16 code units × 2 bytes = 48 bytes (no null terminator)
        let cb_name_required: ULONG = (PROVIDER_NAME_CHARS * size_of::<u16>()) as ULONG;

        // ---------------------------------------------------------------
        // Two-call buffer-negotiation protocol
        // (matches Microsoft USBCryptoProvider sample):
        //
        //   Call 1: SQL Server passes name.ws = NULL, name.cb = 0.
        //           Provider sets name.cb to the required byte count and
        //           returns scp_err_InsufficientBuffer.
        //
        //   Call 2: SQL Server passes name.ws = allocated buffer,
        //           name.cb = buffer size.  Provider fills the struct and
        //           copies the name string into the caller's buffer.
        // ---------------------------------------------------------------
        if info.name.cb < cb_name_required || info.name.ws.is_null() {
            info.name.cb = cb_name_required;
            info!(
                required_cb = cb_name_required,
                caller_cb = info.name.cb,
                "SqlCryptGetProviderInfo: returning InsufficientBuffer (name buffer too small or NULL)"
            );
            return scp_err_InsufficientBuffer;
        }

        // Save the caller's name buffer pointer before overwriting the struct.
        let caller_name_ws = info.name.ws;

        // Build a local ProviderInfo with all the fixed fields.
        // We memcpy the whole struct (as the Microsoft sample does), then
        // restore the caller's ws pointer and copy the string in.
        let mut prov = std::mem::MaybeUninit::<SqlCpProviderInfo>::zeroed().assume_init();

        prov.name.cb = cb_name_required;
        prov.name.ws = PROVIDER_NAME_UTF16.as_ptr() as *mut WCHAR; // temporary, overwritten below

        // Stable GUID {C05A1A00-1001-4001-8001-000000000001}
        prov.guid.Data1 = 0xC05A_1A00u32;
        prov.guid.Data2 = 0x1001u16;
        prov.guid.Data3 = 0x4001u16;
        prov.guid.Data4 = [0x80, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x01];

        prov.version.major = 1;
        prov.version.minor = 0;

        prov.scpVersion.major = 1;
        prov.scpVersion.minor = 1;

        prov.authType = SqlCpAuthType::scp_auth_Basic;
        prov.symmKeySupport = SqlCpKeyFlagsBm::scp_kf_Supported as SqlCpKeyFlags;
        prov.asymmKeySupport = SqlCpKeyFlagsBm::scp_kf_Supported as SqlCpKeyFlags;
        prov.cbKeyThumbLen = size_of::<GUID>() as ULONG; // 16
        prov.fAcceptsKeyName = 1; // TRUE

        // Copy the full struct into the caller's memory (overwrites name.ws)
        std::ptr::copy_nonoverlapping(&prov as *const SqlCpProviderInfo, p_provider_info, 1);

        // Restore the caller's name buffer pointer and copy the name string in
        let info = &mut *p_provider_info;
        info.name.ws = caller_name_ws;
        info.name.cb = cb_name_required;
        if cb_name_required > 0 {
            std::ptr::copy_nonoverlapping(
                PROVIDER_NAME_UTF16.as_ptr(),
                caller_name_ws as *mut u16,
                PROVIDER_NAME_CHARS,
            );
        }

        // --- Diagnostic: hex dump of the entire struct for byte-level analysis ---
        let struct_bytes = std::slice::from_raw_parts(
            p_provider_info as *const u8,
            size_of::<SqlCpProviderInfo>(),
        );
        let hex: String = struct_bytes
            .iter()
            .enumerate()
            .map(|(i, b)| {
                if i > 0 && i % 16 == 0 {
                    format!("\n  {:02x}", b)
                } else {
                    format!(" {:02x}", b)
                }
            })
            .collect();
        info!(
            struct_size = size_of::<SqlCpProviderInfo>(),
            name_cb = info.name.cb,
            name_ws_ptr = ?info.name.ws,
            guid_data1 = format_args!("0x{:08X}", info.guid.Data1),
            version = format_args!("{}.{}.{}.{}", info.version.major, info.version.minor, info.version.build, info.version.revision),
            scp_version = format_args!("{}.{}.{}.{}", info.scpVersion.major, info.scpVersion.minor, info.scpVersion.build, info.scpVersion.revision),
            auth_type = ?info.authType,
            symm = info.symmKeySupport,
            asymm = info.asymmKeySupport,
            thumb_len = info.cbKeyThumbLen,
            accepts_key_name = info.fAcceptsKeyName,
            "SqlCryptGetProviderInfo struct populated (second call)"
        );
        info!(hex = %hex, "SqlCpProviderInfo raw bytes");
    }
    scp_err_Success
}

// ---------------------------------------------------------------------------
// Provider algorithms
// ---------------------------------------------------------------------------

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptGetNextAlgorithmId(p_alg_id: *mut SqlCpAlgId) -> SqlCpError {
    info!("SqlCryptGetNextAlgorithmId called");
    // We have no statically-defined algorithm IDs: all key types are determined
    // at runtime by the KMS. Return NotFound to signal an empty enumeration,
    // which is a valid response (SQL Server simply records that the provider
    // has no built-in algorithm list).
    let _ = p_alg_id;
    scp_err_NotFound
}

#[unsafe(no_mangle)]
pub extern "C" fn SqlCryptGetAlgorithmInfo(
    alg_id: SqlCpAlgId,
    p_algorithm_info: *mut SqlCpAlgorithmInfo,
) -> SqlCpError {
    let _ = (alg_id, p_algorithm_info);
    info!("SqlCryptGetAlgorithmInfo called");
    scp_err_NotSupported
}

